import clsx from 'clsx';

import {
  seriesItemText,
  seriesNameTextMultiLine,
  seriesNameTextMultiLineWrap,
} from '../../../tooltip.sty.js';

export const getNameTextStyle = (
  isSingleLine: boolean,
  multiLine: boolean,
  multiLineMode: 'clamp' | 'wrap' = 'clamp',
): string => {
  const multiLineClass =
    multiLineMode === 'wrap'
      ? seriesNameTextMultiLineWrap
      : seriesNameTextMultiLine;

  if (!isSingleLine) {
    return clsx(seriesItemText, multiLineClass);
  }

  if (multiLine) {
    return multiLineClass;
  }

  return seriesItemText;
};
